#include<bits/stdc++.h>
using namespace std;
int g[500010];
long long f[500010],ans[500010],n,k;
bool flag[500010];
vector<pair<int,int>> mp[500010];
void dfs(int x,int fa=-1)
{
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa)
        {
            dfs(v,x);
            if(f[v]||flag[v])
            {
                f[x]+=f[v]+val*2;
                g[x]=max(g[x],g[v]+val);
            }
        }
    }
}
void calc(int x,int fa)
{
    f[x]=g[x]=0;
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa)
        {
            if(f[v]||flag[v])
            {
                f[x]+=f[v]+val*2;
                g[x]=max(g[x],g[v]+val);
            }
        }
    }
}
void dp(int x,int fa=-1)
{
    ans[x]=f[x]-g[x];
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa)
        {
            calc(x,v);
            calc(v,-1);
            dp(v,x);
            calc(v,x);
            calc(x,-1);
        }
    }
}
int main()
{
    scanf("%d%d",&n,&k);
    for(int i=1;i<n;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    for(int i=1;i<=k;i++)
    {
        int x;
        scanf("%d",&x);
        flag[x]=true;
    }
    dfs(1);
    dp(1);
    for(int i=1;i<=n;i++)
    {
        printf("%lld\n",ans[i]);
    }
    return 0;
}
